class Solution:
    def cutOffTree(self, forest):
        rows = len(forest)
        cols = len(forest[0])
        trees = []
        for r in range(rows):
            for c in range(cols):
                if forest[r][c] > 1:
                    trees.append((forest[r][c], r, c))
        trees.sort()
        def dist(sr, sc, tr, tc):
            if sr == tr and sc == tc:
                return 0
            best = {(sr, sc): 0}
            frontier = [(sr, sc)]
            step = 0
            while frontier:
                step += 1
                nxt = []
                for (r, c) in frontier:
                    for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < rows and 0 <= nc < cols and forest[nr][nc] != 0 and (nr, nc) not in best:
                            best[(nr, nc)] = step
                            if nr == tr and nc == tc:
                                return step
                            nxt.append((nr, nc))
                frontier = nxt
            return -1
        total = 0
        cr, cc = 0, 0
        if forest[0][0] == 0:
            return -1
        for h, tr, tc in trees:
            d = dist(cr, cc, tr, tc)
            if d < 0:
                return -1
            total += d
            cr, cc = tr, tc
        return total

