class Solution:
    def cutOffTree(self, forest):
        from collections import deque
        rows = len(forest)
        cols = len(forest[0])
        if forest[0][0] == 0:
            return -1
        trees = sorted((forest[r][c], r, c) for r in range(rows) for c in range(cols) if forest[r][c] > 1)
        def bfs(sr, sc, tr, tc):
            seen = [[False] * cols for _ in range(rows)]
            q = deque([(sr, sc, 0)])
            seen[sr][sc] = True
            while q:
                r, c, d = q.popleft()
                if r == tr and c == tc:
                    return d
                for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                    nr, nc = r + dr, c + dc
                    if 0 <= nr < rows and 0 <= nc < cols and not seen[nr][nc] and forest[nr][nc] != 0:
                        seen[nr][nc] = True
                        q.append((nr, nc, d + 1))
            return -1
        total = 0
        cr, cc = 0, 0
        for h, tr, tc in trees:
            d = bfs(cr, cc, tr, tc)
            if d < 0:
                return -1
            total += d
            cr, cc = tr, tc
        return total

