var cutOffTree = function(forest) {
    const rows = forest.length, cols = forest[0].length;
    if (forest[0][0] === 0) return -1;
    const trees = [];
    for (let r = 0; r < rows; r++) for (let c = 0; c < cols; c++) if (forest[r][c] > 1) trees.push([forest[r][c], r, c]);
    trees.sort((a, b) => a[0] - b[0]);
    const bfs = (sr, sc, tr, tc) => {
        const seen = Array.from({length: rows}, () => new Array(cols).fill(false));
        const q = [[sr, sc, 0]];
        seen[sr][sc] = true;
        let head = 0;
        const dirs = [[1, 0], [-1, 0], [0, 1], [0, -1]];
        while (head < q.length) {
            const [r, c, d] = q[head++];
            if (r === tr && c === tc) return d;
            for (const [dr, dc] of dirs) {
                const nr = r + dr, nc = c + dc;
                if (nr >= 0 && nr < rows && nc >= 0 && nc < cols && !seen[nr][nc] && forest[nr][nc] !== 0) {
                    seen[nr][nc] = true;
                    q.push([nr, nc, d + 1]);
                }
            }
        }
        return -1;
    };
    let total = 0, cr = 0, cc = 0;
    for (const [h, tr, tc] of trees) {
        const d = bfs(cr, cc, tr, tc);
        if (d < 0) return -1;
        total += d;
        cr = tr; cc = tc;
    }
    return total;
};
